INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  '5f86f054-a538-4ca3-9223-f5542d384071',
  'From Teenage Coder to 5 Million Downloads: The Origin Story of NJD Studio',
  'njd-studio',
  'founder_story',
  'public',
  'Gaming',
  'What began as the passion project of a 12-year-old coder has transformed into a professional gaming studio at the forefront of Saudi Arabia''s eyeball economy.',
  '[{"heading":"The Genesis: A 12-Year-Old''s Vision","pullQuote":"He wasn''t just playing games; he was building the infrastructure for them.","paragraphs":["The story of NJD Studio does not begin in a boardroom, but in the bedroom of a pre-teen enthusiast. Back in 2011, at just 11 or 12 years old, Salman was already deeply immersed in the technical world.","This technical curiosity naturally evolved. By 2016, Salman had transitioned from backend services to full-fledged game development using engines like Unity 4 and 5.","\"Hajwala\" wasn''t just a game; it was a phenomenon that garnered over 5 million downloads with zero spend on user acquisition."]},{"heading":"The Transformation: From \"Salman Studio\" to NJD","paragraphs":["For years, the operation ran under the name \"Salman Studio.\" However, 2022 marked a pivotal shift. Recognizing the need to scale and professionalize, Salman and his co-founder re-established the entity as NJD Games.","The name \"NJD\" is deeply symbolic. It references \"Najd\" (the central region of Saudi Arabia) and represents a desire to simulate the region''s 200-year historical transformation within their company culture."]},{"heading":"\"Closest to the Player\"","pullQuote":"He would personally communicate with players immediately to make changes they requested.","paragraphs":["The defining characteristic of NJD Studio''s success is their obsession with player feedback.","Salman recounts a specific habit that became company culture: he would personally communicate with players immediately to make changes they requested.","If the community votes for a specific car model, the team listens. They even test concepts by releasing 3D renders on social media before full development."]},{"heading":"Cultural Resonance: The Secret Sauce","pullQuote":"They create an emotional connection with players that foreign studios cannot replicate.","paragraphs":["Why did NJD''s racing games succeed where others failed? The answer lies in cultural authenticity.","NJD Studio leverages their local advantage. By including hyper-local details—such as King Abdullah Street—they create an emotional connection with players that foreign studios cannot replicate.","This authenticity fosters incredible retention."]},{"heading":"Key Takeaway","paragraphs":["The story of NJD Studio is a masterclass in organic growth. By combining technical expertise with an authentic respect for local culture and an open channel to their community, Salman turned a childhood hobby into a leading Saudi gaming studio."]}]'::jsonb,
  '{"intro":"In the rapidly evolving landscape of the Saudi Arabian gaming industry, few stories are as compelling as that of NJD Studio. What began as the passion project of a 12-year-old coder has transformed into a professional gaming studio at the forefront of the region''s eyeball economy.","company":"NJD Studio","founder":"Salman","milestones":[{"icon":"💻","year":"2011","title":"First Lines of Code","description":"At just 12 years old, Salman begins offering cloud services and backend networking for gamers."},{"icon":"🎮","year":"2016","title":"Game Development Begins","description":"Transitions from backend services to full game development using Unity engine."},{"icon":"🚀","year":"2018","title":"Hajwala Goes Viral","description":"Hits 5 million downloads with zero marketing spend — pure organic growth."},{"icon":"🏢","year":"2022","title":"NJD Studio is Born","description":"Rebrands from Salman Studio to NJD Games, signaling professional scale and ambition."},{"icon":"🌍","year":"2024","title":"Going Global","description":"New title Drift Tuner targets international markets in Japan and Brazil."}]}'::jsonb,
  'Saudi Arabia',
  '2026-02-14T09:48:53.308459+00:00',
  '2026-02-14T09:48:53.308459+00:00'
) ON CONFLICT (id) DO UPDATE SET
