INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  'f945d2bd-a56d-446d-9fa6-e858fe7e5849',
  'From Passion to Production: The Story of Fahy Studios and the Rise of Saudi Gaming',
  'fahy-studios',
  'founder_story',
  'public',
  'Gaming',
  'How a Pokemon-fueled childhood dream, Vision 2030, and a strategic pivot to hybrid casual gaming built one of Saudi Arabia''s most promising production studios.',
  '[{"heading":"The Origin: A Pokemon-Fueled Dream","pullQuote":"He didn''t just play; he began modding Pokemon games, rewriting narratives, and designing characters.","paragraphs":["Every great studio has an origin story rooted in passion, and for Hani, the co-founder of Fahy Studios, that spark began with the Nintendo 64.","In his teenage years, Hani didn''t just play; he began modding Pokemon games, rewriting narratives, and designing characters.","However, the cultural landscape of the time had different plans. The expectation was rigid: become an engineer, a doctor, or a banker."]},{"heading":"The Catalyst: Vision 2030","pullQuote":"It was no longer just a childhood hobby; it was a sanctioned, supported industry.","paragraphs":["The turning point for Fahy Studios wasn''t just personal; it was national. With Vision 2030, gaming was identified as a strategic focus sector.","Hani reached out to his childhood friend, Fahad, and they decided to take a serious stab at the industry. Fahy Studios was born."]},{"heading":"What''s in a Name?","paragraphs":["The name \"Fahy\" describes someone who is \"zoned out\" or too deep in their own head—essentially, the state of flow a gamer enters when hyper-focused on play."]},{"heading":"The First Lesson: Ambition vs. Reality","pullQuote":"They paused the complex project and focused on shipping a complete product.","paragraphs":["The studio''s first project served as a critical learning experience. The team quickly realized their debut concept was too massive for a three-person team.","They made a mature pivot: they paused the complex project and focused on shipping Smash and Dash, a hyper-casual endless runner."]},{"heading":"The Strategic Pivot: Hybrid Casual and Global Partnerships","paragraphs":["Fahy Studios recognized that the Hyper-Casual market was becoming saturated. They pivoted toward Hybrid Casual games.","They partnered with Kwalee, a UK-based giant, allowing Fahy to focus on building great games while leveraging global expertise."]},{"heading":"The Future: A Sustainable Production House","paragraphs":["Today, Fahy Studios is building a sustainable production house capable of consistently churning out successful titles. From modding Pokemon roms in a bedroom to closing deals with UK publishers, their story is a blueprint for the new wave of Saudi entrepreneurs."]}]'::jsonb,
  '{"intro":"In the rapidly evolving landscape of the Middle East''s digital economy, few sectors are witnessing as much explosive growth as gaming. At the heart of this transformation in Riyadh is Fahy Studios.","company":"Fahy Studios","founder":"Hani","milestones":[{"icon":"🕹️","year":"2000s","title":"Pokemon Sparked a Dream","description":"Hani begins modding Pokemon games and running text-based RPGs on gaming forums."},{"icon":"💼","year":"2010s","title":"The Corporate Years","description":"Studies MIS and enters the corporate world with PwC and Saudi Electricity Company."},{"icon":"🎯","year":"2020","title":"Vision 2030 Catalyst","description":"Saudi gaming becomes a strategic sector. Hani reunites with co-founder Fahad."},{"icon":"📱","year":"2021","title":"First Game Ships","description":"After pivoting from an overly ambitious debut, Smash and Dash launches successfully."},{"icon":"🤝","year":"2023","title":"Global Partnership","description":"Partners with UK publisher Kwalee to scale distribution and user acquisition."}]}'::jsonb,
  'Saudi Arabia',
  '2026-02-14T09:49:12.786895+00:00',
  '2026-02-14T09:49:12.786895+00:00'
) ON CONFLICT (id) DO UPDATE SET
