INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  '8bba8a12-8703-4930-8e4b-d7d4a88c78d8',
  'Success Is Rented, Not Owned: The Resilient Rise of Sir Alain Edene',
  'alain-edene',
  'founder_story',
  'public',
  'Healthcare',
  'From sweeping gym floors in Scotland to co-founding premier fitness clubs in Saudi Arabia, Sir Alain Edene''s journey offers a masterclass in humility and ambition.',
  '[{"heading":"The Broken Dream","pullQuote":"With damaged knees and ankles, the career he had built his identity around was over.","paragraphs":["Alain''s story begins in Cameroon, born into a poor family with a singular ambition: to become a professional football player and buy his mother a car.","For a year, he was lost. He tried working on oil rigs but eventually walked away."]},{"heading":"The Power of \"Yes\"","pullQuote":"He arrived at 5:30 AM every morning and cleaned with the same discipline he applied to sports.","paragraphs":["Alain walked into a JJB Sports Gym in Scotland and asked for a job as an instructor. He was rejected immediately.","He returned the next day, rejected again. On the third day, the manager offered him the only role available: a cleaner.","Alain said \"Yes.\" He arrived at 5:30 AM every morning and cleaned with the same discipline he applied to sports. When an instructor position opened up, he was the natural choice."]},{"heading":"The Saudi Opportunity","pullQuote":"He arrived in Saudi Arabia knowing nothing about the country.","paragraphs":["In 2008, Alain applied online for a job at a football academy in Jeddah.","A neighbor introduced him to a VIP client. Alain impressed him so much that he ended up training the man and his entire extended family for ten years.","He eventually founded Adene Fitness (2016-2018), a niche, high-end gym in Jeddah."]},{"heading":"Philosophy on Business and Leadership","pullQuote":"Building a team is like driving a bus. First, you must get the right people on the bus.","paragraphs":["Alain''s transition from trainer to founder was driven by a desire to professionalize the industry.","His leadership philosophy: building a team is like driving a bus—first, get the right people on the bus, then decide where they sit."]},{"heading":"\"Rent is Due Every Day\"","pullQuote":"Success is never owned, it is rented. And rent is due every day.","paragraphs":["He quotes: \"Success is never owned, it is rented. And rent is due every day.\"","He believes resilience is a muscle. Whether you are a CEO or a cleaner, life is hard."]},{"heading":"The Future","paragraphs":["Today, Sir Alain is focused on giving back through mentorship and consultancy. His advice: find a mentor who has the scars, learn from their mistakes, and take the faster route to the mountaintop."]}]'::jsonb,
  '{"intro":"In the world of entrepreneurship, we often hear about overnight successes. But the reality is usually a much longer, grittier road paved with rejection, reinvention, and relentless hard work.","company":"Fittin International","founder":"Sir Alain Edene","milestones":[{"icon":"⚽","year":"Early","title":"The Football Dream","description":"Born in Cameroon, Alain pursues semi-professional football in Scotland before injuries end his career."},{"icon":"🧹","year":"2005","title":"Said Yes to Cleaning","description":"Takes a janitor role at JJB Sports Gym after being rejected twice as an instructor."},{"icon":"✈️","year":"2008","title":"Lands in Saudi Arabia","description":"Applies online for a football academy job in Jeddah."},{"icon":"🏋️","year":"2016","title":"Founds Adene Fitness","description":"Launches a high-end gym in Jeddah running back-to-back sessions from dawn till dusk."},{"icon":"🌟","year":"2020","title":"Fittin International","description":"Scales to a full wellness consultancy."}]}'::jsonb,
  'Saudi Arabia',
  '2026-02-14T09:49:45.447785+00:00',
  '2026-02-15T17:21:19.796767+00:00'
) ON CONFLICT (id) DO UPDATE SET
