INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  '98311506-4159-443a-903b-96cc3d99c943',
  'Rooted in Resilience: How Treehouse Became Riyadh''s Favorite Farm-to-Table Café',
  'treehouse',
  'founder_story',
  'public',
  'E-Commerce',
  'What started as a childhood memory of a family farm in Al Qassim has grown into one of Riyadh''s most beloved farm-to-table concepts.',
  '[{"heading":"The Origin: A Memory from Al Qassim","pullQuote":"She wanted to bring that same honest, real food to a wider audience in Riyadh.","paragraphs":["For Lulwah Al Juraiban, the concept is deeply personal. It is rooted in her childhood memories of Eid holidays spent at her family''s farm in Al Qassim.","A family member was diagnosed with cancer, and doctors advised clean, organic nutrition. Seeing the tangible impact of clean eating, Lulwah realized there was a gap in the market."]},{"heading":"The Launch: Opening on Day One of Lockdown","pullQuote":"What did I do?","paragraphs":["Treehouse opened in March 2020, on the very morning that the COVID-19 lockdown was announced in Riyadh.","Remarkably, the lockdown created a captive audience hyper-conscious about health. Treehouse sold out every single day."]},{"heading":"The Double Life: Corporate by Day, Founder by Night","pullQuote":"She is unapologetic about missing late-night social gatherings to prioritize rest and work.","paragraphs":["Lulwah is not just a founder; she is a full-time corporate employee in IT operations. For over a decade, she has maintained a demanding 9-to-5 while building her business."]},{"heading":"The Philosophy: The Farm Writes the Menu","pullQuote":"If an ingredient isn''t in season, it simply doesn''t appear on the menu.","paragraphs":["\"The farm writes the menu,\" Lulwah explains. If an ingredient isn''t in season, it simply doesn''t appear on the menu.","This philosophy extends to a deep respect for food waste. Treehouse utilizes ugly vegetables and incorporates stems and scraps into broths."]},{"heading":"The Future","paragraphs":["Today, Treehouse has expanded to multiple locations and a thriving catering business. Lulwah''s advice: Don''t wait for a manual, because one doesn''t exist."]}]'::jsonb,
  '{"intro":"In Riyadh, where the dining scene is dominated by flashy trends and international franchises, Treehouse stands as a testament to authenticity.","company":"Treehouse","founder":"Lulwah Al Juraiban","milestones":[{"icon":"🌳","year":"Childhood","title":"The Original Treehouse","description":"Eid holidays at the family farm in Al Qassim plant the seeds of a future business."},{"icon":"🥗","year":"2018","title":"Clean Eating Mission","description":"A family health crisis reveals the power of organic nutrition."},{"icon":"🔥","year":"2020","title":"Opens on Day One of Lockdown","description":"Launches the very morning COVID lockdown hits — and sells out every single day."},{"icon":"🏪","year":"2022","title":"Multiple Locations","description":"Expands across Riyadh with a thriving catering business."}]}'::jsonb,
  'Saudi Arabia',
  '2026-02-14T09:49:45.447785+00:00',
  '2026-02-14T09:49:45.447785+00:00'
) ON CONFLICT (id) DO UPDATE SET
