INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  'c8ea605e-9d25-460c-9dd4-3e437b3446c7',
  'Leading the Feast: Faisal Shaker''s Vision for Saudi Arabia''s Culinary Future',
  'faisal-shaker',
  'founder_story',
  'public',
  'E-Commerce',
  'From a seasoned career in corporate banking to helming one of the Kingdom''s most prestigious restaurant groups, Faisal''s journey is a masterclass in leadership and adaptation.',
  '[{"heading":"From Banking to Banquets","pullQuote":"He traded financial portfolios for menus, stepping in to lead MFC full-time.","paragraphs":["Faisal''s story begins far from the kitchen. He pursued Business Administration and Economics, eventually landing in banking at Merrill Lynch, SABB, and Audi Capital for over 15 years.","In 2012, while still in banking, Faisal and his partners formed MFC. By 2017, he made the hard decision to leave banking behind."]},{"heading":"The Nozomi Lesson: A Blessing in Disguise","pullQuote":"Success isn''t just about buying a franchise; it''s about the team''s ability to execute and adapt.","paragraphs":["MFC''s first major venture was bringing Nozomi to Riyadh in 2014.","Just five months after opening, the original London location closed. Instead of panicking, they doubled down and turned it into a flagship success."]},{"heading":"The Art of Adaptation","pullQuote":"Saudi diners like to see and be seen.","paragraphs":["Saudi diners like to see and be seen—Faisal emphasizes open layouts over closed partitions.","The Saudi palette favors bold, rich flavors over subtle ones."]},{"heading":"Operations: No Vacations","pullQuote":"Operations means no vacations.","paragraphs":["\"Operations means no vacations,\" he says. His day starts at 7:30 AM and often ends past 8:00 PM.","He views his role as a facilitator for his 1,700+ employees."]},{"heading":"The Future: A Booming Kingdom","pullQuote":"The hardest part isn''t reaching the top. It''s staying there.","paragraphs":["With Vision 2030, Expo 2030, and the World Cup on the horizon, the F&B sector is exploding with opportunity.","For MFC, the recipe for staying on top: constant innovation, respect for local culture, and a championship-level team."]}]'::jsonb,
  '{"intro":"In the high-stakes world of fine dining, consistency is the ultimate currency. This is the philosophy that drives Faisal Shaker, the co-founder and CEO of Modern Food Company.","company":"Modern Food Company","founder":"Faisal Shaker","milestones":[{"icon":"🏦","year":"2000s","title":"15 Years in Banking","description":"Climbs the corporate ladder at Merrill Lynch, SABB, and Audi Capital."},{"icon":"🍽️","year":"2012","title":"MFC is Founded","description":"While still in banking, Faisal and partners form Modern Food Company."},{"icon":"🥢","year":"2014","title":"Nozomi Riyadh Opens","description":"Brings the London-based Japanese concept to Saudi Arabia."},{"icon":"🚪","year":"2017","title":"Leaves Banking for Good","description":"Goes all-in on MFC, managing 1,700+ employees."},{"icon":"🏆","year":"2030","title":"Expo & World Cup Era","description":"Positioning MFC as a leading F&B group for Saudi Arabia''s mega-events."}]}'::jsonb,
  'Saudi Arabia',
  '2026-02-14T09:50:10.555528+00:00',
  '2026-02-14T09:52:20.18679+00:00'
) ON CONFLICT (id) DO UPDATE SET
