INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  'e7a6a118-ff96-4947-bcd9-9c71fe815c9e',
  'The Architect of Startups: Hassan Ikram on Building Resilience and Success in Saudi Arabia',
  'hassan-ikram',
  'founder_story',
  'public',
  'Consultancy',
  'From corporate finance at Morgan Stanley to founding Cotyledon Management Consultancy, Hassan Ikram''s journey offers a masterclass in resilience, strategic growth, and turning failure into a stepping stone.',
  '[{"heading":"The Serial Founder''s Origin","pullQuote":"His first venture—a restaurant in Bahrain—was purchased while he was still a sophomore in university.","paragraphs":["Hassan''s entrepreneurial journey didn''t wait for a graduation ceremony. His first venture—a restaurant in Bahrain—was purchased while still a sophomore.","Despite a successful 11-year stint in investment banking, the itch to build never left. A medical facility venture in the UAE in 2014 became one of his most valuable lessons.","He views failed founders not as liabilities, but as seasoned assets who know exactly what not to do."]},{"heading":"Cotyledon: A Three-Pillar Ecosystem","pullQuote":"They raised 5 million SAR in less than an hour.","paragraphs":["Cotyledon operates on three pillars: Consultancy, Investment, and Venture Building.","Under Cotyledon''s guidance, Saudi Kitchens grew sales to over 57 million SAR and raised 5 million SAR in less than an hour through crowdfunding."]},{"heading":"Navigating the Saudi Market: Insider Tips","pullQuote":"Don''t just start a business; start a business that aligns with the government''s goals.","paragraphs":["Align with Vision 2030. Leverage government support: The Code, Monsha''at, and Hadaf subsidies.","Hassan recently received over 900 vetted candidates through Fintech Saudi''s internship program at zero cost."]},{"heading":"The Myth of Work-Life Balance","pullQuote":"Take the time off. Mental sanity is a long-term asset.","paragraphs":["For years, Hassan operated on 18-20 hour workdays. A health scare forced him to confront burnout.","His advice now: Take the time off. Mental sanity is a long-term asset."]},{"heading":"Final Thoughts","pullQuote":"Hard work eventually pays off—just don''t give up on the drive.","paragraphs":["Hassan''s philosophy: Resilience is key. For those who do their research, leverage the ecosystem, and prioritize their well-being, the opportunities in Saudi Arabia are limitless."]}]'::jsonb,
  '{"intro":"In the thriving ecosystem of Saudi Arabia''s Vision 2030, few figures embody the spirit of serial entrepreneurship quite like Hassan Ikram.","company":"Cotyledon Management Consultancy","founder":"Hassan Ikram","milestones":[{"icon":"🍕","year":"University","title":"First Business as a Sophomore","description":"Buys a restaurant in Bahrain while still studying."},{"icon":"📊","year":"2003","title":"11 Years in Investment Banking","description":"Builds deep financial expertise at Morgan Stanley."},{"icon":"🏥","year":"2014","title":"The UAE Medical Venture","description":"A medical facility venture fails — but delivers invaluable lessons."},{"icon":"🌱","year":"2020","title":"Cotyledon is Born","description":"Launches a three-pillar startup ecosystem."},{"icon":"💰","year":"2024","title":"SAR 5M Raised in Under an Hour","description":"Portfolio company raises crowdfunding in record time."}]}'::jsonb,
  'Saudi Arabia',
  '2026-02-14T09:50:10.555528+00:00',
  '2026-02-14T09:50:10.555528+00:00'
) ON CONFLICT (id) DO UPDATE SET
