INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  '63d8ed72-e7bb-4652-833d-446e43b51766',
  'The Long Game: Building a Business from Community Roots in Saudi Arabia',
  'race-arabia',
  'founder_story',
  'public',
  'Sports & Events',
  'In the burgeoning sports economy of Saudi Arabia, Race Arabia stands as a case study in organic growth and passion-led entrepreneurship. Founded by Nezar Al-Tuwaijri, the company transitioned from a grassroots running club into the Kingdom''s premier organizer of world-class endurance events.',
  '[{"heading":"The Pivot: From Community to Commercial Entity","pullQuote":"There was plenty of energy but nowhere to channel it. The market lacked structured goals—races—for these new athletes.","paragraphs":["Race Arabia didn''t start with a business plan; it started on the pavement. Nezar initially founded the R7 Run Club (running 7 days a week), which grew organically from three friends to over a thousand members.","The business insight came when he realized the market lacked structured goals—races—for these new athletes. Nezar identified a gap between participation (people running) and monetization (organized events). He didn''t rush to sell; he built the community first, creating a built-in customer base before the company even existed."]},{"heading":"Navigating the First Mover Disadvantage","pullQuote":"Being the first in a market is often romanticized, but there is no proof of concept.","paragraphs":["Being the first in a market is often romanticized, but Nezar highlights the brutal reality: There is no proof of concept.","In a market accustomed to endurance events being free community initiatives, convincing sponsors and participants to pay was a significant hurdle. Nezar had to educate the market on the value of professional logistics, safety, and experience.","Early mistakes included getting approvals from people who weren''t actual decision-makers, leading to cancelled events. The lesson learned was to ruthlessly verify authority and secure everything in writing, especially when dealing with complex permits for public spaces."]},{"heading":"Experience is King: The Hiring Strategy","pullQuote":"Only a runner knows the desperation of reaching an aid station or the emotion of the finish line.","paragraphs":["In the events industry, logistical perfection is the baseline, not the differentiator. Nezar argues that ''Experience is King.''","He prioritizes hiring team members who are active participants in the sport. Only a runner knows the desperation of reaching an aid station or the emotion of the finish line.","The energy of the staff dictates the energy of the participants. If the organizers view it as ''just a job,'' the event feels sterile. If they are enthusiasts, that energy becomes infectious and turns customers into advocates."]},{"heading":"The 360-Degree Feedback Loop","pullQuote":"Every complaint is a data point for growth.","paragraphs":["Scaling from small fun runs to International Trail Races in AlUla requires a rigorous commitment to improvement. Race Arabia implements a 360-degree evaluation after every single event.","Feedback is aggregated not just from participants via surveys, but also from internal teams, vendors, and government stakeholders.","Nezar views every complaint as a data point for growth. This feedback loop is what allowed them to scale operations from hundreds of runners to thousands without collapsing under logistical weight."]},{"heading":"Strategic Partnerships as Accelerators","pullQuote":"Partnering with major entities allowed Race Arabia to level up faster than they could have alone.","paragraphs":["While organic growth is healthy, Nezar emphasizes that strategic partnerships act as necessary accelerants.","Partnering with major entities like the Royal Commission for AlUla (RCU) allowed Race Arabia to level up faster than they could have alone. These partnerships provided the funding and stage to test their operational limits, moving them from local organizers to international standard-bearers.","The goal is now to move from event execution to event tourism—creating race calendars far enough in advance (12+ months) to attract international athletes, aligning directly with Vision 2030''s tourism goals."]},{"heading":"Conclusion","paragraphs":["Race Arabia''s success wasn''t an overnight sprint; it was an ultramarathon. By prioritizing community trust, obsessing over the participant experience, and navigating the regulatory landscape with patience, Nezar Al-Tuwaijri has built a sustainable business model in a sector that is just hitting its stride.","For entrepreneurs in Saudi Arabia, the message is clear: Build the community, and the market will follow."]}]'::jsonb,
  '{"intro":"In the burgeoning sports economy of Saudi Arabia, Race Arabia stands as a case study in organic growth and passion-led entrepreneurship. Founded by Nezar Al-Tuwaijri, the company transitioned from a grassroots running club into the Kingdom''s premier organizer of world-class endurance events. His journey offers critical insights for entrepreneurs looking to build in uncharted markets.","company":"Race Arabia","founder":"Nezar Al-Tuwaijri","milestones":[{"year":"2016","title":"R7 Run Club Founded","description":"Started with three friends running seven days a week, growing organically to over a thousand members."},{"year":"2018","title":"Race Arabia Launched","description":"Transitioned from community run club to a commercial entity organizing structured endurance events."},{"year":"2021","title":"AlUla Trail Race","description":"Partnered with the Royal Commission for AlUla to organize international-standard trail races."},{"year":"2024","title":"Event Tourism Vision","description":"Scaling towards 12+ month race calendars to attract international athletes, aligning with Vision 2030 tourism goals."}]}'::jsonb,
  'Saudi Arabia',
  '2026-02-14T17:35:02.875425+00:00',
  '2026-02-14T17:35:02.875425+00:00'
) ON CONFLICT (id) DO UPDATE SET
