INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  'ff4ebd33-b71f-4bbf-a3de-8bab0d248a6f',
  'Two Devs, One Dream: The "Just Do It" Spirit Behind Duwit',
  'duwit-studio',
  'rising_founder',
  'public',
  'Gaming',
  'After losing control of a hit game to investors, two Indonesian founders sold everything and moved to Riyadh to rebuild — on their own terms.',
  '[{"heading":"The Catalyst: Algorithms and Hostile Takeovers","pullQuote":"I have the records of the original board game... the records of people testing my game.","paragraphs":["Duwit was born from two distinct, painful lessons that shaped the founders'' philosophy.","For Alfi, the lesson was about ownership. After a previous venture ended in a \"hostile takeover,\" he lost control of the work he had built. That experience instilled in him a rigorous discipline for documentation and IP protection. \"I have the records of the original board game... the records of people testing my game,\" Alfi says, ensuring that this time, their creation remains their own.","For Banu, the lesson was about stability. A talented developer, Banu had previously found success in the mobile gaming market. However, a sudden algorithm change on the Google Play Store slashed his game''s revenue to one-third overnight.","Realizing that the mobile Free-to-Play (F2P) market was too dependent on volatile platform algorithms and expensive user acquisition, the duo decided to pivot. They joined forces to explore new opportunities in Saudi Arabia, specifically targeting the premium PC market where quality, rather than algorithms, dictates success."]},{"heading":"The \"All-In\" Move to Riyadh","pullQuote":"You cannot attract money without a real product. Make sure you have a good product first.","paragraphs":["For Alfi and Banu, the move to Saudi Arabia wasn''t just a business trip—it was a survival strategy. Participating in the Saudi Game Champions incubator, the team is betting everything on the region''s growing ecosystem.","\"I sold my car... there is no accommodation, so I just go here,\" Alfi explains regarding the initial struggle to get established.","They are currently finalizing their Corporate Responsibility (CR) status to unlock a 200,000 SAR grant that will help stabilize the company. However, Alfi warns other founders not to see the region as easy money. \"You cannot attract money without a real product,\" he advises. \"Make sure you have a good product first\"."]},{"heading":"The Game: Chess Nuke","pullQuote":"It''s impossible to do mobile with two people.","paragraphs":["Duwit''s flagship title, Chess Nuke, is a strategy game born from a physical board game designed by the founders. They converted it into a digital prototype in just over a month and are currently testing it with 200 users.","Informed by Banu''s past experience with mobile volatility, Duwit is taking a Steam first, Mobile later approach.","\"It''s impossible to do mobile with two people,\" Alfi notes, citing the massive costs of user acquisition and live ops required for free-to-play markets. By focusing on a premium single-player experience for Desktop (targeting an August release), they plan to build a portfolio and capital before expanding."]},{"heading":"Man vs. Machine: A Unique Stance on AI","pullQuote":"You need a human for the vision.","paragraphs":["In an industry rushing to replace artists with algorithms, Duwit draws a hard line.","\"For assets, I am strictly not using AI,\" Alfi declares. He cites the importance of maintaining an artistic \"soul\" and avoiding the \"bad press\" and visibility issues on Steam associated with generative art.","However, they are using AI to empower their technical workflow. Using tools like JetBrains and Gemini, the two-man team uses AI as \"junior testers\" to check code and speed up development. \"The wrong approach is thinking ''I have AI so I don''t need a programmer,''\" Alfi says. \"That''s stupid... You need a human for the vision\"."]},{"heading":"\"Just Do It\"","paragraphs":["The road ahead is steep. The team is managing legal hurdles, finalizing the game''s UI, and preparing for a massive launch—all while navigating a new country. But the spirit of Duwit (a play on the Indonesian slang for money and the slogan \"Just Do It\") is about action.","They aren''t waiting for permission. They are building, documenting, and proving that with enough grit, two people can rebuild their dream anywhere in the world."]}]'::jsonb,
  '{"intro":"\"Don''t trust words, trust numbers.\" This is the hard-earned mantra of Akhmad Alfi Zainuddin, co-founder of the indie game studio Duwit. It is a lesson learned in the trenches of the gaming industry, where he and his co-founder, Banu Andaru Adhimuka, discovered that talent alone isn''t enough you need control. Now, the duo is all-in on Riyadh. They have left their homes in Indonesia and liquidated assets—including Alfi''s personal car to fund their dream. United in Saudi Arabia, they are building a studio founded on resilience and a strategic pivot away from the volatile mobile market.","company":"Duwit","founder":"Akhmad Alfi Zainuddin & Banu Andaru Adhimuka"}'::jsonb,
  'Saudi Arabia',
  '2026-02-17T09:12:03.835366+00:00',
  '2026-02-17T10:26:04.372678+00:00'
) ON CONFLICT (id) DO UPDATE SET
