INSERT INTO public.articles (id, title, slug, type, status, category, excerpt, content, metadata, country, created_at, updated_at)
VALUES (
  '76ba8097-c88f-43f7-a2fb-472d3fd2366c',
  'Beyond the ''Freemium'' Trap: Engineering a Saudi-Born Global Action-RPG',
  'sabahjar-studio',
  'rising_founder',
  'public',
  'Gaming',
  'Sabahjar Studio is bypassing the mobile market to build a premium Action-Roguelike for PC, rooted in authentic Arabian mythology.',
  '[{"heading":null,"paragraphs":["In the MENA gaming market, the \"safe\" bet is well-understood: build for mobile, optimize for low-end devices, and monetize via aggressive microtransactions. It is a volume game.","Sabahjar Studio is taking a different, riskier path. Founded in January 2025, the Riyadh-based team is bypassing the local mobile market entirely to build a premium, mechanically complex Action-Roguelike for PC.","Their debut title, Djinn Scrolls, represents a test case for the Saudi ecosystem: Can a local studio successfully compete in the global \"$20 Steam game\" tier against established indie giants?"]},{"heading":"The Pivot: From 700 Million Views to Zero Players","paragraphs":["The studio''s leadership team, Bandar Majrashi (CEO) and Nour Aldeen Alqalalwah (Art Director), are not traditional game developers. They are veterans of the Saudi animation industry, best known for their work on Masameer, the Myrkott-produced series that surpassed 700 million views and secured distribution on Netflix.","This background provides the studio with a distinct \"unfair advantage\" in art direction, but it also presents a learning curve. \"We don''t want to copy-paste demons from the West,\" notes Majed Altaemi, the studio''s CTO and technical lead.","The transition from non-interactive animation to reactive game design is significant. Despite massive animation reach, game development forces them to rebuild audience, tooling, and production discipline from scratch. While the art asset quality is high, the challenge for Sabahjar has been translating that visual fidelity into gameplay that feels responsive. The team is betting that their \"Authentic Djinn\" aesthetic — rooted in smokeless fire and regional tribal lore — will provide enough differentiation to stand out in a crowded market."]},{"heading":"Technical Differentiation: The Scroll System","pullQuote":"We don''t want to copy-paste demons from the West.","paragraphs":["Mechanically, Djinn Scrolls positions itself in the \"Action-Roguelike\" genre, citing Hades and Path of Exile as benchmarks. This is a high bar; both titles are known for near-perfect combat loops.","Sabahjar''s core differentiator is the \"Scroll System.\" Rather than a standard skill tree, the game uses a combinatorial mechanic where abilities are chained via \"scrolls.\" Scrolls are socketed pre-run and modified during roguelike loops, creating exponential build paths.","Input: A basic slash. Modifier: Player links a \"Fire Scroll.\" Trigger: On critical hit, cast \"Earth Spike.\"","This system aims to create \"standardized creativity,\" allowing players to engineer their own combat builds. The technical risk (polishing a complex combinatorial system) lies in balancing: these systems are notoriously difficult to debug and prone to being \"broken\" by players in ways developers didn''t anticipate."]},{"heading":"The PC First Thesis","paragraphs":["Why reject the headline-lucrative mobile market? The founders argue it is a matter of unit economics.","\"The mobile market is incredibly expensive to break into,\" the team notes. In the current \"Post-IDFA\" mobile landscape, User Acquisition (UA) costs have skyrocketed. For a bootstrapped or seed-stage studio, the marketing budget required to acquire a profitable mobile user base is often prohibitive.","By targeting Steam (PC), Sabahjar Studio is betting on a \"high-retention, lower-volume\" model. They don''t need millions of casual downloads; they need a dedicated community of 50,000–100,000 hardcore players willing to pay an upfront premium price."]},{"heading":"The Risk Profile","paragraphs":["Despite the strong vision, the path ahead is fraught with execution risk.","Market Saturation: In 2024 alone, over 14,000 games were released on Steam. Standing out requires more than just good art; it requires a \"marketing hook.\" Successful indie titles typically need 50,000+ wishlists before launch to guarantee visibility on Steam''s \"Popular Upcoming\" list.","The \"Last 10%\" Trap: The team has achieved a Vertical Slice (50% functional completion). However, in game development, the final 10% (polishing, bug-fixing, and balancing) often consumes 50% of the timeline.","Conversion Reality: Even with strong interest, typical indie wishlist-to-purchase conversion rates hover between 5% and 15%. This leaves little margin for error in launch marketing."]},{"heading":"Ecosystem Context","paragraphs":["Sabahjar Studio is currently incubated at SGC2 (Saudi Game Center), one of the Kingdom''s primary game incubation programs under the Ministry of Communications and Information Technology that selects top teams for mentorship and funding.","Backed by a 200,000 SAR grant, the studio has the runway to reach its next milestone. But capital is only fuel. The ultimate test will be whether a team of master animators can master the brutal logic of game mechanics.","If they succeed, Djinn Scrolls won''t just be a hit game; it will be a blueprint for how Saudi studios can export culture, not just consume it."]}]'::jsonb,
  '{"stage":"Incubator","company":"Sabahjar Studio","founder":"Bandar Majrashi, Nour Aldeen Alqalalwah & Majed Altaemi","website":null,"linkedin":null,"oneLiner":"Building Djinn Scrolls — a premium PC Action-Roguelike rooted in Arabian mythology, incubated at SGC2."}'::jsonb,
  'Saudi Arabia',
  '2026-02-17T14:33:46.286729+00:00',
  '2026-02-17T14:36:13.63465+00:00'
) ON CONFLICT (id) DO UPDATE SET
